package com.ichi2.anki.preferences

import androidx.preference.PreferenceCategory
import com.ichi2.anki.R
import com.ichi2.anki.cardviewer.CommandGroup
import com.ichi2.anki.cardviewer.ViewerCommand
import com.ichi2.anki.reviewer.MappableBinding.Companion.toPreferenceString
import com.ichi2.preferences.ControlPreference

class ControlsSettingsFragment : SettingsFragment() {
    override val preferenceResource: Int
        get() = R.xml.preferences_controls
    override val analyticsScreenNameConstant: String
        get() = "prefs.controls"

    override fun initSubscreen() {
        addAllControlPreferencesToCategory()
    }

    /**
     * Creates [PreferenceCategory] for each [CommandGroup] and attaches
     * all possible [ControlPreference] elements to their respective category
     */
    private fun addAllControlPreferencesToCategory() {
        // Group commands by their CommandGroup
        val commandsByGroup = ViewerCommand.values().groupBy { it.group }

        // Sort groups by their order and create categories
        val sortedGroups = CommandGroup.values().sortedBy { it.order }

        for (group in sortedGroups) {
            val commands = commandsByGroup[group] ?: continue

            // Create a PreferenceCategory for this group
            val category = PreferenceCategory(requireContext()).apply {
                setTitle(group.titleRes)
                key = "controls_category_${group.name}"
            }
            preferenceScreen.addPreference(category)

            // Add all commands in this group to the category
            for (command in commands) {
                val preference = ControlPreference(category.context).apply {
                    setTitle(command.resourceId)
                    key = command.preferenceKey
                    setDefaultValue(command.defaultValue.toPreferenceString())
                }
                category.addPreference(preference)
            }
        }
    }
}"}

