package com.ichi2.anki.cardviewer

import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.greaterThan
import org.hamcrest.Matchers.hasSize
import org.junit.Test

/**
 * Tests for [CommandGroup] and the grouping of [ViewerCommand]s
 */
class CommandGroupTest {

    @Test
    fun `all commands are assigned to a group`() {
        // Every ViewerCommand should have a group assigned
        val commandsWithGroup = ViewerCommand.values().filter { it.group != null }
        assertThat(
            "All commands should have a group assigned",
            commandsWithGroup.toList(),
            hasSize(ViewerCommand.values().size)
        )
    }

    @Test
    fun `all groups have at least one command`() {
        // Every CommandGroup should have at least one command
        val commandsByGroup = ViewerCommand.values().groupBy { it.group }
        for (group in CommandGroup.values()) {
            val commands = commandsByGroup[group] ?: emptyList()
            assertThat(
                "Group ${group.name} should have at least one command",
                commands.size,
                greaterThan(0)
            )
        }
    }

    @Test
    fun `command groups have unique order values`() {
        val orders = CommandGroup.values().map { it.order }
        val uniqueOrders = orders.distinct()
        assertThat(
            "All command groups should have unique order values",
            uniqueOrders,
            hasSize(orders.size)
        )
    }
}
"}

